VALUES
  ('pukao-0c700c30-moex-00274', 'pukao-0c700c30', 'pukao-0c700c30-moex-110-6948958a', 'sub-pukao-0c700c30-02', NULL, 'single_choice', '被污染的湖邊有10棟房屋，每棟租金為20,000元。在其他類似的湖邊沒有污染的房屋，每月租金為40,000元。 湖水之所以被污染，是因為湖邊有家食品加工廠在湖中傾倒廢棄物。為了解決污染問題，加工廠可以加裝 價值150,000元的機器，並將水中的污染減少到可以忽略不計。以上敘述所涉及的外部成本的值為：', '["20,000元", "150,000元", "200,000元", "400,000元"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:50+00:00", "source_pdf_sha1": "c4d2194ea576", "answer_pdf_sha1": "b28a0b151639", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "416", "s": "1009", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 31, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "統計"}'::jsonb, NULL),
  ('pukao-0c700c30-moex-00275', 'pukao-0c700c30', 'pukao-0c700c30-moex-110-6948958a', 'sub-pukao-0c700c30-02', NULL, 'single_choice', '由於國家公園的遊客過多，導致生態環境惡化，野生動、植物都大量減少。為解決以上的困境，請問下列 何種方案較可能有效的解決國家公園所面臨的問題？', '["降低遊憩設施的舒適程度", "增加野生動植物的野放與種植", "提高國家公園的門票價格", "減少國家公園的管理人員以及設施維護"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:50+00:00", "source_pdf_sha1": "c4d2194ea576", "answer_pdf_sha1": "b28a0b151639", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "416", "s": "1009", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 32, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "統計"}'::jsonb, NULL),
  ('pukao-0c700c30-moex-00276', 'pukao-0c700c30', 'pukao-0c700c30-moex-110-6948958a', 'sub-pukao-0c700c30-02', NULL, 'single_choice', '需求拉動型通貨膨脹將造成：', '["物價水準提升但不改變實質GDP", "同時使物價水準及實質GDP提升", "物價水準提升但降低實質GDP", "總合供給曲線（aggregatesupplycurve）向右移動"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:50+00:00", "source_pdf_sha1": "c4d2194ea576", "answer_pdf_sha1": "b28a0b151639", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "416", "s": "1009", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 33, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "統計"}'::jsonb, NULL),
  ('pukao-0c700c30-moex-00277', 'pukao-0c700c30', 'pukao-0c700c30-moex-110-6948958a', 'sub-pukao-0c700c30-02', NULL, 'single_choice', '我國針對某進口電子產品進行研發，取得創新與國際競爭力，並開始出口該電子產品，則下列敘述何者正確？', '["創新後，我國在該電子產品的生產上一定有絕對利益", "創新後，我國在該產品的生產上一定沒有絕對利益", "創新前，我國生產該產品的機會成本一定比較高", "創新前，我國生產該產品的機會成本一定比較低"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:50+00:00", "source_pdf_sha1": "c4d2194ea576", "answer_pdf_sha1": "b28a0b151639", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "416", "s": "1009", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 34, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "統計"}'::jsonb, NULL),
  ('pukao-0c700c30-moex-00278', 'pukao-0c700c30', 'pukao-0c700c30-moex-110-6948958a', 'sub-pukao-0c700c30-02', NULL, 'single_choice', '根據總合供給與總合需求模型，下列各項景氣衝擊何者可能造成停滯性通膨？', '["技術進步", "大地震", "出口衰退", "消費者信心增強"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:50+00:00", "source_pdf_sha1": "c4d2194ea576", "answer_pdf_sha1": "b28a0b151639", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "416", "s": "1009", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 35, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "統計"}'::jsonb, NULL),
  ('pukao-0c700c30-moex-00279', 'pukao-0c700c30', 'pukao-0c700c30-moex-110-6948958a', 'sub-pukao-0c700c30-02', NULL, 'single_choice', '外銷訂單指數、失業率、企業用電量、股價指數等4項中，屬於順循環且是領先指標有幾項？', '["0項", "1項", "2項", "3項"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:50+00:00", "source_pdf_sha1": "c4d2194ea576", "answer_pdf_sha1": "b28a0b151639", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "416", "s": "1009", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 36, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "統計"}'::jsonb, NULL),
  ('pukao-0c700c30-moex-00280', 'pukao-0c700c30', 'pukao-0c700c30-moex-110-6948958a', 'sub-pukao-0c700c30-02', NULL, 'single_choice', '根據新古典經濟成長模型，其他條件不變下，人口成長率提高，長期將導致下列何項結果？', '["總產出下降", "平均每人產出下降", "平均每人資本增加", "平均每人儲蓄率增加"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:50+00:00", "source_pdf_sha1": "c4d2194ea576", "answer_pdf_sha1": "b28a0b151639", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "416", "s": "1009", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 37, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "統計"}'::jsonb, NULL),
  ('pukao-0c700c30-moex-00281', 'pukao-0c700c30', 'pukao-0c700c30-moex-110-6948958a', 'sub-pukao-0c700c30-02', NULL, 'single_choice', '有關於凱因斯模型與實質景氣循環模型對於景氣循環看法的比較，下列敘述何者正確？', '["凱因斯模型認為勞動市場處於失衡狀態；實質景氣循環模型認為勞動市場處於均衡狀態", "凱因斯模型強調供給面衝擊；實質景氣循環模型著重需求面衝擊", "凱因斯模型適用於解釋未預期到的衝擊；實質景氣循環模型適用於預期到的衝擊", "凱因斯模型認為均衡所得可透過利率調整而達成；實質景氣循環模型認為均衡所得可透過物價調整達成"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:50+00:00", "source_pdf_sha1": "c4d2194ea576", "answer_pdf_sha1": "b28a0b151639", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "416", "s": "1009", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 38, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "統計"}'::jsonb, NULL),
  ('pukao-0c700c30-moex-00282', 'pukao-0c700c30', 'pukao-0c700c30-moex-110-6948958a', 'sub-pukao-0c700c30-02', NULL, 'single_choice', '根據新古典經濟成長模型，若考量持續的技術進步，長期穩定時，每人平均產出將會出現下列何項結果？', '["固定不變", "持續上升", "持續下降", "成長率大於儲蓄率"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:50+00:00", "source_pdf_sha1": "c4d2194ea576", "answer_pdf_sha1": "b28a0b151639", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "416", "s": "1009", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 39, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "統計"}'::jsonb, NULL),
  ('pukao-0c700c30-moex-00283', 'pukao-0c700c30', 'pukao-0c700c30-moex-110-6948958a', 'sub-pukao-0c700c30-02', NULL, 'single_choice', '若一國的物品與服務之出口與進口，各為1,500億美元和1,200億美元，利息收入淨額為負20億美元，國 外移轉所得淨額為零，對外投資500億美元，以及外人投資為400億美元。根據前述資訊，該國的金融帳 餘額為：', '["淨流入180億美元", "淨流出100億美元", "淨流入100億美元", "淨流出380億美元"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:50+00:00", "source_pdf_sha1": "c4d2194ea576", "answer_pdf_sha1": "b28a0b151639", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "416", "s": "1009", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 40, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "統計"}'::jsonb, NULL)
